<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller; use App\Http\Requests\Admin\StoreProjectRequest; use App\Http\Requests\Admin\UpdateProjectRequest; use App\Models\Project; use App\Models\ProjectCategory; use App\Services\FileUploadService; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\Cache; use Illuminate\View\View;
class ProjectController extends Controller { public function index(Request $request): View { $items=Project::query()->with('category')->when($request->filled('search'),fn($q)=>$q->where(fn($qq)=>$qq->where('title','like','%'.$request->search.'%')->orWhere('slug','like','%'.$request->search.'%')->orWhere('short_description','like','%'.$request->search.'%')))->when($request->filled('category'),fn($q)=>$q->where('project_category_id',$request->integer('category')))->when($request->filled('status'),fn($q)=>$q->where('status',(bool)$request->integer('status')))->when($request->filled('featured'),fn($q)=>$q->where('is_featured',(bool)$request->integer('featured')))->ordered()->paginate(15)->withQueryString(); $categories=ProjectCategory::query()->ordered()->get(); return view('admin.pages.projects.index',compact('items','categories')); } public function create(): View { $categories=ProjectCategory::query()->ordered()->get(); return view('admin.pages.projects.form',['item'=>new Project(['progress_percentage'=>0]),'categories'=>$categories]); } public function store(StoreProjectRequest $request, FileUploadService $uploader): RedirectResponse { $data=$this->payload($request->validated()); $data['featured_image']=$uploader->replace($request->file('featured_image'),null,'uploads/projects'); Project::create($data); $this->clearCache(); return redirect()->route('admin.projects.index')->with('success','Project created successfully.'); } public function edit(Project $project): View { $categories=ProjectCategory::query()->ordered()->get(); return view('admin.pages.projects.form',['item'=>$project,'categories'=>$categories]); } public function update(UpdateProjectRequest $request, Project $project, FileUploadService $uploader): RedirectResponse { $data=$this->payload($request->validated()); $data['featured_image']=$uploader->replace($request->file('featured_image'),$project->featured_image,'uploads/projects'); $project->update($data); $this->clearCache(); return redirect()->route('admin.projects.index')->with('success','Project updated successfully.'); } public function destroy(Project $project): RedirectResponse { $project->delete(); $this->clearCache(); return back()->with('success','Project deleted successfully.'); } private function payload(array $data): array { $data['status']=(bool)($data['status']??false); $data['is_featured']=(bool)($data['is_featured']??false); $data['sort_order']=(int)($data['sort_order']??0); return $data; } private function clearCache(): void { foreach(['projects_active_ordered','projects_featured_ordered','project_categories_active_ordered','homepage_projects_featured','homepage_sections'] as $key) Cache::forget($key); } }
